insert into public.escala_definicoes (codigo, nome, versao, schema_json) values
  ('HADS', 'Escala Hospitalar de Ansiedade e Depressão (HADS)', 'v1', '{"code":"HADS","name":"Escala Hospitalar de Ansiedade e Depressão (HADS)","version":"v1","items":[{"id":"A1","text":"Eu me sinto tenso ou contraído","type":"radio","options":[0,1,2,3]},{"id":"D2","text":"Eu ainda sinto gosto pelas mesmas coisas de antes","type":"radio","options":[0,1,2,3]},{"id":"A3","text":"Eu sinto uma espécie de medo, como se alguma coisa ruim fosse acontecer","type":"radio","options":[0,1,2,3]},{"id":"D4","text":"Dou risada e me divirto quando vejo coisas engraçadas","type":"radio","options":[0,1,2,3]},{"id":"A5","text":"Estou com a cabeça cheia de preocupações","type":"radio","options":[0,1,2,3]},{"id":"D6","text":"Eu me sinto alegre","type":"radio","options":[0,1,2,3]},{"id":"A7","text":"Consigo ficar sentado à vontade e me sentir relaxado","type":"radio","options":[0,1,2,3]},{"id":"D8","text":"Eu estou lento para pensar e fazer as coisas","type":"radio","options":[0,1,2,3]},{"id":"A9","text":"Eu tenho uma sensação ruim de medo (frio na barriga/aperto no estômago)","type":"radio","options":[0,1,2,3]},{"id":"D10","text":"Eu perdi o interesse em cuidar da minha aparência","type":"radio","options":[0,1,2,3]},{"id":"A11","text":"Eu me sinto inquieto, como se eu não pudesse ficar parado","type":"radio","options":[0,1,2,3]},{"id":"D12","text":"Fico esperando animado as coisas boas que estão por vir","type":"radio","options":[0,1,2,3]},{"id":"A13","text":"De repente, tenho a sensação de entrar em pânico","type":"radio","options":[0,1,2,3]},{"id":"D14","text":"Consigo sentir prazer ao assistir/ler/ouvir algo","type":"radio","options":[0,1,2,3]}],"scoring":{"method":"sum","subscales":{"anxiety":["A1","A3","A5","A7","A9","A11","A13"],"depression":["D2","D4","D6","D8","D10","D12","D14"]}}}'::jsonb)
insert into public.escala_definicoes (codigo, nome, versao, schema_json) values
  ('DN4', 'Questionário para Diagnóstico de Dor Neuropática 4 (DN4)', 'v1', '{"code":"DN4","name":"Questionário para Diagnóstico de Dor Neuropática 4 (DN4)","version":"v1","items":[{"id":"Q1_1","text":"Queimação","type":"boolean"},{"id":"Q1_2","text":"Sensação de frio dolorosa","type":"boolean"},{"id":"Q1_3","text":"Choque elétrico","type":"boolean"},{"id":"Q2_4","text":"Formigamento","type":"boolean"},{"id":"Q2_5","text":"Alfinetada e agulhada","type":"boolean"},{"id":"Q2_6","text":"Adormecimento","type":"boolean"},{"id":"Q2_7","text":"Coceira","type":"boolean"},{"id":"Q3_8","text":"Hipoestesia ao toque","type":"boolean"},{"id":"Q3_9","text":"Hipoestesia à picada de agulha","type":"boolean"},{"id":"Q4_10","text":"Escovação desencadeia/aumenta dor","type":"boolean"}],"scoring":{"method":"sum_boolean","threshold":4}}'::jsonb)
insert into public.escala_definicoes (codigo, nome, versao, schema_json) values
  ('MOS_SLEEP', 'Escala do Sono (MOS)', 'v1', '{"code":"MOS_SLEEP","name":"Escala do Sono (MOS)","version":"v1","items":[{"id":"S1","text":"Tempo para iniciar o sono (1=0-15min ... 5=>60min)","type":"radio","options":[1,2,3,4,5]},{"id":"S2","text":"Horas de sono por noite (número)","type":"number","min":0,"max":24},{"id":"S3","text":"Sono não era tranquilo","type":"radio","options":[1,2,3,4,5,6]},{"id":"S4","text":"Dormiu o suficiente para acordar descansado","type":"radio","options":[1,2,3,4,5,6]},{"id":"S5","text":"Acordou com falta de ar ou dor de cabeça","type":"radio","options":[1,2,3,4,5,6]},{"id":"S6","text":"Sentiu sono/sonolento durante o dia","type":"radio","options":[1,2,3,4,5,6]},{"id":"S7","text":"Teve dificuldade para dormir","type":"radio","options":[1,2,3,4,5,6]},{"id":"S8","text":"Acordou à noite e teve dificuldade para voltar a dormir","type":"radio","options":[1,2,3,4,5,6]},{"id":"S9","text":"Dificuldade para permanecer acordado durante o dia","type":"radio","options":[1,2,3,4,5,6]},{"id":"S10","text":"Roncou durante a noite","type":"radio","options":[1,2,3,4,5,6]},{"id":"S11","text":"Tirou cochilos (>=5 min) durante o dia","type":"radio","options":[1,2,3,4,5,6]},{"id":"S12","text":"Obteve a quantidade de sono de que precisava","type":"radio","options":[1,2,3,4,5,6]}],"scoring":{"method":"basic_summary"}}'::jsonb)
insert into public.escala_definicoes (codigo, nome, versao, schema_json) values
  ('MCGILL_BRIEF', 'McGill breve (descritores + intensidade)', 'v1', '{"code":"MCGILL_BRIEF","name":"McGill breve (descritores + intensidade)","version":"v1","items":[{"id":"M1","text":"Latejante","type":"boolean"},{"id":"M2","text":"Pontada","type":"boolean"},{"id":"M3","text":"Choque","type":"boolean"},{"id":"M4","text":"Fina-Agulhada","type":"boolean"},{"id":"M5","text":"Fisgada","type":"boolean"},{"id":"M6","text":"Queimação","type":"boolean"},{"id":"M7","text":"Espalha","type":"boolean"},{"id":"M8","text":"Dolorida","type":"boolean"},{"id":"M9","text":"Cansativa-exaustiva","type":"boolean"},{"id":"M10","text":"Enjoada","type":"boolean"},{"id":"M11","text":"Sufocante","type":"boolean"},{"id":"M12","text":"Apavorante-Enlouquecedora","type":"boolean"},{"id":"M13","text":"Aborrecida","type":"boolean"},{"id":"M14","text":"Que incomoda","type":"boolean"},{"id":"M15","text":"Insuportável","type":"boolean"},{"id":"VAS","text":"Intensidade da dor (0-10)","type":"number","min":0,"max":10}],"scoring":{"method":"count_present_and_vas"}}'::jsonb)
insert into public.escala_definicoes (codigo, nome, versao, schema_json) values
  ('PCS_BR', 'Escala de Catastrofismo Associado à Dor (13 itens)', 'v1', '{"code":"PCS_BR","name":"Escala de Catastrofismo Associado à Dor (13 itens)","version":"v1","items":[{"id":"P1","text":"Item 1","type":"radio","options":[1,2,3,4]},{"id":"P2","text":"Item 2","type":"radio","options":[1,2,3,4]},{"id":"P3","text":"Item 3","type":"radio","options":[1,2,3,4]},{"id":"P4","text":"Item 4","type":"radio","options":[1,2,3,4]},{"id":"P5","text":"Item 5","type":"radio","options":[1,2,3,4]},{"id":"P6","text":"Item 6","type":"radio","options":[1,2,3,4]},{"id":"P7","text":"Item 7","type":"radio","options":[1,2,3,4]},{"id":"P8","text":"Item 8","type":"radio","options":[1,2,3,4]},{"id":"P9","text":"Item 9","type":"radio","options":[1,2,3,4]},{"id":"P10","text":"Item 10","type":"radio","options":[1,2,3,4]},{"id":"P11","text":"Item 11","type":"radio","options":[1,2,3,4]},{"id":"P12","text":"Item 12","type":"radio","options":[1,2,3,4]},{"id":"P13","text":"Item 13","type":"radio","options":[1,2,3,4]}],"scoring":{"method":"sum"}}'::jsonb)
insert into public.escala_definicoes (codigo, nome, versao, schema_json) values
  ('MDS_UPDRS_TOTAL', 'MDS-UPDRS (Totais por Parte I–IV) - Rotina', 'v1', '{"code":"MDS_UPDRS_TOTAL","name":"MDS-UPDRS (Totais por Parte I–IV) - Rotina","version":"v1","items":[{"id":"P1_TOTAL","text":"Parte I - experiências não motoras (total)","type":"number","min":0},{"id":"P2_TOTAL","text":"Parte II - experiências motoras (total)","type":"number","min":0},{"id":"P3_TOTAL","text":"Parte III - exame motor (total)","type":"number","min":0},{"id":"P4_TOTAL","text":"Parte IV - complicações motoras (total)","type":"number","min":0}],"scoring":{"method":"sum_fields","fields":["P1_TOTAL","P2_TOTAL","P3_TOTAL","P4_TOTAL"]}}'::jsonb)
insert into public.escala_definicoes (codigo, nome, versao, schema_json) values
  ('BARTHEL_MOD', 'Índice de Barthel Modificado', 'v1', '{"code":"BARTHEL_MOD","name":"Índice de Barthel Modificado","version":"v1","items":[{"id":"HIGIENE","text":"Higiene Pessoal","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":1},{"label":"Ajuda moderada","value":3},{"label":"Ajuda mínima","value":4},{"label":"Independente","value":5}]},{"id":"BANHO","text":"Banho","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":1},{"label":"Ajuda moderada","value":3},{"label":"Ajuda mínima","value":4},{"label":"Independente","value":5}]},{"id":"ALIMENTACAO","text":"Alimentação","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":2},{"label":"Ajuda moderada","value":5},{"label":"Ajuda mínima","value":8},{"label":"Independente","value":10}]},{"id":"TOALETE","text":"Toalete","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":2},{"label":"Ajuda moderada","value":5},{"label":"Ajuda mínima","value":8},{"label":"Independente","value":10}]},{"id":"ESCADAS","text":"Subir escadas","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":2},{"label":"Ajuda moderada","value":5},{"label":"Ajuda mínima","value":8},{"label":"Independente","value":10}]},{"id":"VESTUARIO","text":"Vestuário","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":2},{"label":"Ajuda moderada","value":5},{"label":"Ajuda mínima","value":8},{"label":"Independente","value":10}]},{"id":"BEXIGA","text":"Controle de Bexiga","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":2},{"label":"Ajuda moderada","value":5},{"label":"Ajuda mínima","value":8},{"label":"Independente","value":10}]},{"id":"INTESTINO","text":"Controle de Intestino","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":2},{"label":"Ajuda moderada","value":5},{"label":"Ajuda mínima","value":8},{"label":"Independente","value":10}]},{"id":"MOBILITY_MODE","text":"Mobilidade: o paciente deambula ou utiliza cadeira de rodas?","type":"radio","options":[{"label":"Deambulação (andar)","value":"WALK"},{"label":"Cadeira de rodas","value":"WHEEL"}]},{"id":"DEAMBULACAO","text":"Deambulação (se aplicável)","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":3},{"label":"Ajuda moderada","value":8},{"label":"Ajuda mínima","value":12},{"label":"Independente","value":15}]},{"id":"CADEIRA_RODAS","text":"Cadeira de rodas (se aplicável)","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":1},{"label":"Ajuda moderada","value":3},{"label":"Ajuda mínima","value":4},{"label":"Independente","value":5}]},{"id":"TRANSFERENCIA","text":"Transferência cadeira/cama","type":"radio","options":[{"label":"Incapaz","value":0},{"label":"Ajuda substancial","value":3},{"label":"Ajuda moderada","value":8},{"label":"Ajuda mínima","value":12},{"label":"Independente","value":15}]}],"scoring":{"method":"barthel_weighted"}}'::jsonb)
insert into public.escala_definicoes (codigo, nome, versao, schema_json) values
  ('FIQ', 'Questionário Sobre o Impacto da Fibromialgia (FIQ)', 'v1', '{"code":"FIQ","name":"Questionário Sobre o Impacto da Fibromialgia (FIQ)","version":"v1","items":[{"id":"F1_1","text":"1a) Fazer compras","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"F1_2","text":"1b) Lavar roupa","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"F1_3","text":"1c) Cozinhar","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"F1_4","text":"1d) Lavar louça","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"F1_5","text":"1e) Limpar a casa","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"F1_6","text":"1f) Arrumar a cama","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"F1_7","text":"1g) Andar vários quarteirões","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"F1_8","text":"1h) Visitar parentes/amigos","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"F1_9","text":"1i) Cuidar do quintal/jardim","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"F1_10","text":"1j) Dirigir carro/andar de ônibus","type":"radio","options":[{"label":"Quase sempre","value":0},{"label":"Sempre","value":1},{"label":"De vez em quando","value":2},{"label":"Nunca","value":3}]},{"id":"DAYS_WELL","text":"2) Nos últimos 7 dias, em quantos dias você se sentiu bem? (0-7)","type":"number","min":0,"max":7},{"id":"DAYS_MISSED","text":"3) Por causa da fibromialgia, quantos dias você faltou ao trabalho? (0-7)","type":"number","min":0,"max":7},{"id":"WORK_INTERFERENCE","text":"4) Interferência na capacidade de fazer seu serviço (0-10)","type":"number","min":0,"max":10},{"id":"PAIN","text":"5) Quanta dor você sentiu? (0-10)","type":"number","min":0,"max":10},{"id":"FATIGUE","text":"6) Você sentiu cansaço? (0-10)","type":"number","min":0,"max":10},{"id":"MORNING_TIRED","text":"7) Como se sentiu ao se levantar de manhã? (0-10)","type":"number","min":0,"max":10},{"id":"STIFFNESS","text":"8) Você sentiu rigidez? (0-10)","type":"number","min":0,"max":10},{"id":"ANXIETY","text":"9) Você se sentiu nervoso/ansioso? (0-10)","type":"number","min":0,"max":10},{"id":"DEPRESSION","text":"10) Você se sentiu deprimido/desanimado? (0-10)","type":"number","min":0,"max":10}],"scoring":{"method":"fiq_summary"}}'::jsonb)
